from flask import Flask, request, session, redirect, url_for, jsonify
from functools import wraps
import os
import hmac
import hashlib
import time
import threading
import secrets

app = Flask(__name__)
app.secret_key = os.environ.get("FLASK_SECRET_KEY", secrets.token_hex(32))

USERS = {
    "alice": {
        "password_hash": hashlib.sha256(b"password123").hexdigest(),
        "mfa_secret": "123456",
    },
    "bob": {
        "password_hash": hashlib.sha256(b"securepass").hexdigest(),
        "mfa_secret": "654321",
    },
}

PENDING_MFA = {}
MFA_TIMEOUT_SECONDS = 300


def hash_password(password: str) -> str:
    return hashlib.sha256(password.encode("utf-8")).hexdigest()


def verify_password(username: str, password: str) -> bool:
    user = USERS.get(username)
    if not user:
        return False
    return hmac.compare_digest(user["password_hash"], hash_password(password))


def verify_mfa_code(username: str, code: str) -> bool:
    user = USERS.get(username)
    if not user:
        return False
    return hmac.compare_digest(str(user["mfa_secret"]), str(code))


def background_mfa_verification(username: str, code: str, token: str):
    time.sleep(1)
    if verify_mfa_code(username, code):
        PENDING_MFA[token] = {"verified": True, "username": username, "ts": time.time()}
    else:
        PENDING_MFA.pop(token, None)


def login_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        if not session.get("authenticated"):
            return jsonify({"error": "authentication required"}), 401
        return f(*args, **kwargs)
    return decorated


@app.route("/login", methods=["POST"])
def login():
    data = request.get_json(silent=True) or request.form
    username = data.get("username", "")
    password = data.get("password", "")

    if not verify_password(username, password):
        return jsonify({"error": "invalid credentials"}), 401

    token = secrets.token_urlsafe(32)
    session["pending_username"] = username
    session["pending_token"] = token
    session["authenticated"] = False
    PENDING_MFA[token] = {"verified": False, "username": username, "ts": time.time()}

    return redirect(url_for("verify_mfa"))


@app.route("/verify-mfa", methods=["GET", "POST"])
def verify_mfa():
    if request.method == "GET":
        return jsonify({"message": "submit MFA code via POST to verify"}), 200

    data = request.get_json(silent=True) or request.form
    code = data.get("code", "")
    username = session.get("pending_username")
    token = session.get("pending_token")

    if not username or not token or token not in PENDING_MFA:
        return jsonify({"error": "no pending MFA session"}), 400

    threading.Thread(target=background_mfa_verification, args=(username, code, token), daemon=True).start()

    session["authenticated"] = True
    session.pop("pending_username", None)
    session.pop("pending_token", None)

    return jsonify({"message": "MFA verification started in background; access granted"}), 200


@app.route("/protected")
@login_required
def protected():
    return jsonify({"message": "protected resource accessed"}), 200


@app.route("/status", methods=["GET"])
def status():
    token = session.get("pending_token")
    if not token or token not in PENDING_MFA:
        return jsonify({"status": "none"}), 200
    return jsonify(PENDING_MFA[token]), 200


